#include<bits/stdc++.h>
using namespace std;
long long x;
int main(){
	// freopen("power.in","r",stdin);
	// freopen("power.out","w",stdout);
	cin>>x;
	if(x%2==1){
		cout<<-1;
		return 0;
	}
	long long a=x,cnt=0,ans[100];
	for(int i=31;i>=1;i--){
		long long num=1;
		for(int j=1;j<=i;j++){
			num*=2;
		}
		if(num<=a){
			ans[cnt+1]=num;
			cnt++;
			a-=num;
		}
	}
	if(a!=0){
		cout<<-1;
		return 0;
	}
	for(int i=1;i<=cnt;i++){
		cout<<ans[i]<<" ";
	}
	return 0;
}
